INSERT INTO preguntas_frecuentes (pregunta, respuesta, categoria) VALUES
                                                                      ('¿Cómo recibo mi juego después de comprarlo?', 'Si es un juego digital (como una key de Steam), recibirás el código en tu correo al instante. Si es un juego físico, se despachará a tu domicilio a través de nuestra logística.', 'Compras y Envíos'),
                                                                      ('¿Aceptan devoluciones o reembolsos?', 'Sí, para juegos digitales tienes 14 días para solicitar un reembolso siempre y cuando el código no haya sido canjeado. Para físicos, aplica la garantía legal de 6 meses en Chile.', 'Soporte y Garantía'),
                                                                      ('¿Cuándo repondrán el stock de títulos populares como Terraria o Battlefield 1?', 'Nuestro catálogo se actualiza semanalmente. Te recomendamos agregar los juegos a tu Wishlist para recibir una notificación automática cuando vuelvan a estar disponibles.', 'Inventario'),
                                                                      ('¿Qué hago si mi código de activación no funciona?', 'Por favor, abre un ticket en nuestro portal de Soporte adjuntando tu número de pedido y capturas de pantalla del error. Te responderemos en menos de 24 horas.', 'Soporte Técnico'),
                                                                      ('¿Los precios incluyen IVA?', 'Sí, todos los precios mostrados en la tienda ya incluyen los impuestos correspondientes.', 'Pagos');